const item = $input.first().json.body || {};
const nombre = (item.nombre || '').trim().replace(/\s+/g, ' ');
const email = (item.email || '').toLowerCase().trim();
const presupuesto = parseInt(item.presupuesto) || 0;
const urg = ['alta', 'media', 'baja'];
const urgencia = urg.includes((item.urgencia || '').toLowerCase()) ? item.urgencia.toLowerCase() : 'media';
const svcs = ['desarrollo_web', 'ecommerce', 'app_movil', 'automatizacion', 'diseno_ui', 'consultoria', 'soporte'];
const servicio = svcs.includes((item.servicio || '').toLowerCase()) ? item.servicio.toLowerCase() : 'desarrollo_web';
const errores = [];
if (!email.includes('@')) errores.push('email invalido');
if (nombre.length < 2) errores.push('nombre muy corto');
if (presupuesto <= 0) errores.push('presupuesto invalido');
if (errores.length) throw new Error('Validacion fallida: ' + errores.join(', '));
const ts = Date.now();
const rand = Math.random().toString(36).substring(2, 6).toUpperCase();
return [{ json: {
  lead_id: 'LD-' + ts + '-' + rand,
  nombre: nombre,
  email: email,
  presupuesto: presupuesto,
  urgencia: urgencia,
  servicio: servicio,
  telefono: (item.telefono || '').trim(),
  descripcion: (item.descripcion || '').trim().substring(0, 2000),
  fuente: item.fuente || 'webhook'
} }];

const l = $input.first().json;
let score = 0;
const b = parseInt(l.presupuesto) || 0;
if (b >= 5000) score += 40;
else if (b >= 2000) score += 30;
else if (b >= 1000) score += 20;
else if (b >= 300) score += 10;
score += ({ alta: 30, media: 15, baja: 5 }[l.urgencia] || 5);
score += ({ desarrollo_web: 20, ecommerce: 20, app_movil: 18, automatizacion: 18, diseno_ui: 15, consultoria: 12, soporte: 5 }[l.servicio] || 8);
if (l.telefono && l.telefono.length > 6) score += 5;
if (l.descripcion && l.descripcion.length > 50) score += 5;
const tier = score >= 70 ? 'HOT' : score >= 40 ? 'WARM' : 'COLD';
return [{ json: Object.assign({}, l, { score: score, tier: tier }) }];

