const items = $input.all();
const out = [];
for (const it of items) {
  const f = it.json;
  const dias = parseInt(f.dias_al_vencimiento);
  let nivel, asunto, cuerpo;
  if (dias === 3) { nivel = 'RECORDATORIO'; asunto = 'Recordatorio: Factura ' + f.factura_id + ' vence en 3 dias'; cuerpo = '<p>Hola <b>' + f.cliente + '</b>, tu factura <b>' + f.factura_id + '</b> por $' + f.monto + ' USD vence pronto.</p>'; }
  else if (dias === 0) { nivel = 'HOY'; asunto = 'Tu factura ' + f.factura_id + ' vence HOY'; cuerpo = '<p>Hola <b>' + f.cliente + '</b>, la factura <b>' + f.factura_id + '</b> vence hoy. Agradezco el pago a la brevedad.</p>'; }
  else if (dias < 0 && dias >= -3) { nivel = 'VENCIDA'; asunto = 'Factura ' + f.factura_id + ' vencida'; cuerpo = '<p>Hola <b>' + f.cliente + '</b>, la factura <b>' + f.factura_id + '</b> esta vencida hace ' + Math.abs(dias) + ' dia(s).</p>'; }
  else if (dias < -3) { nivel = 'URGENTE'; asunto = 'URGENTE: Factura ' + f.factura_id; cuerpo = '<p>Hola <b>' + f.cliente + '</b>, la factura lleva ' + Math.abs(dias) + ' dias vencida. Es necesario regularizarla.</p>'; }
  else continue;
  out.push({ json: Object.assign({}, f, { nivel_urgencia: nivel, email_asunto: asunto, email_cuerpo: cuerpo, dias_al_vencimiento: dias }) });
}
return out;

